import sys
import json
from kafka import KafkaAdminClient
from kafka.admin import NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, configs=config)
    admin_client.create_topics([topic])
    print(f"Topic '{topic_name}' created with {num_partitions} partitions and replication factor {replication_factor}.")

def main():
    if len(sys.argv) < 5:
        print("Usage: python kafka_admin.py <bootstrap_servers> <topic_name> <num_partitions> <replication_factor> <config_json>")
        sys.exit(1)

    bootstrap_servers = sys.argv[1]
    topic_name = sys.argv[2]
    num_partitions = int(sys.argv[3])
    replication_factor = int(sys.argv[4])
    config_json = sys.argv[5]

    with open(config_json) as config_file:
        config = json.load(config_file)

    admin_client = KafkaAdminClient(bootstrap_servers=bootstrap_servers)

    create_topic(admin_client, topic_name, num_partitions, replication_factor, config)

    admin_client.close()

if __name__ == "__main__":
    main()